<template>
	<view>
		<status-bar />
		<view class="header-wrap">
			<view class="back-btn" @click="$util.back()">
				<u-image :src="$util.img('/statics/uni/img/common/icon_back.svg')" mode="widthFix"></u-image>
			</view>
		</view>
		<view class="foot" :style="{'background-image': `url(${$util.img('/statics/images/cps/bg.png')})`}">
			<view class="content">
				<view class="item" v-for="item,index in list" :key="index" @click="$util.on(item.link)">
					<u-image class="img" :src="$util.img(item.img)" width="106rpx" height="106rpx"></u-image>
					<text class="name">{{item.title}}</text>
					<text class="tips">{{item.desc}}</text>
				</view>
			</view>
		</view>
	</view>
</template>

<script>
	import StatusBar from '@/components/my-page-header/status-bar'
	export default {
		components: {
			'status-bar': StatusBar
		},
		data() {
			return {
				list: [],
			};
		},
		onLoad() {
			this.loadData()
		},
		methods: {
			async loadData() {
				const res = await this.$u.api.cpsList()
				this.list = res
			}
		}
	}
</script>

<style lang="scss" scoped scoped>
	.header-wrap {
		height: 88rpx;
		background-color: #fc5022;
		display: flex;
		align-items: center;

		.back-btn {
			display: inline-block;
			height: 60rpx;
			width: 60rpx;
			margin-left: 20rpx;
			position: fixed;
		}
	}

	.foot {
		height: calc(100vh - 88rpx);
		background-size: 100%;
		background-position: top;
		background-repeat: no-repeat;
		padding: 130rpx 20rpx 0 20rpx;

		.content {
			width: 100%;
			background: #FFFFFF;
			border-radius: 10rpx;
			display: flex;
			flex-wrap: wrap;
			gap: 10rpx;
			width: 100%;
			margin: 0 auto;
			padding: 30rpx 0;

			.item {
				width: calc(25% - 10rpx);
				display: flex;
				align-items: center;
				flex-direction: column;

				.img {
					width: 106rpx;
					border-radius: 50%;
				}

				.name {
					margin-top: 10rpx;
					font-size: 24rpx;
					font-weight: 500;
					color: #191e2e;
				}

				.tips {
					font-size: 20rpx;
					font-weight: 400;
					color: #9b9fa8;
					white-space: nowrap;
				}
			}
		}
	}
</style>